    if (!landmarks || landmarks.length === 0) return 'neutral';

    const wrist = landmarks[0];
    const middleMCP = landmarks[9]; // Middle finger knuckle

    // Calculate scale reference (Wrist to Knuckle distance)
    const scale = Math.hypot(middleMCP.x - wrist.x, middleMCP.y - wrist.y);

    if (scale === 0) return 'neutral';

    // Check extended status of 4 fingers (Index to Pinky)
    // Indices: Index(8), Middle(12), Ring(16), Pinky(20)
    // Corresponding PIP joints: 6, 10, 14, 18
    const fingers = [
        { tip: 8, pip: 6 },
        { tip: 12, pip: 10 },
        { tip: 16, pip: 14 },
        { tip: 20, pip: 18 }
    ];

    let extendedCount = 0;

    fingers.forEach(({ tip: tipIdx, pip: pipIdx }) => {
      const tip = landmarks[tipIdx];
      const pip = landmarks[pipIdx];

      const dTip = Math.hypot(tip.x - wrist.x, tip.y - wrist.y);
      const dPip = Math.hypot(pip.x - wrist.x, pip.y - wrist.y);

      // If tip is further from wrist than PIP by a margin, consider extended
      if (dTip > dPip * 1.1) {
          extendedCount++;
      }
    });

    // Determine state
    // Open: 4 or 5 fingers extended (Thumb is variable, so we focus on 4 main fingers)
    if (extendedCount >= 4) return 'open';

    // Fist: 0 fingers extended
    if (extendedCount === 0) return 'fist';

    // Pointing / Two Fingers: 1 or 2 fingers extended
    // Usually Index (1) or Index+Middle (2)
    if (extendedCount === 1 || extendedCount === 2) return 'pointing';

    return 'neutral';
  };

  const predictWebcam = () => {
    if (!landmarkerRef.current || !videoRef.current || !canvasRef.current) return;

    // Safety check for video readiness
    if (videoRef.current.videoWidth === 0 || videoRef.current.videoHeight === 0) {
