import React, { useEffect, useRef, useState } from 'react';
import { FilesetResolver, HandLandmarker, HandLandmarkerResult } from '@mediapipe/tasks-vision';

interface GestureControllerProps {
  onControl: (dx: number, dy: number, gestureType: 'rotate' | 'zoom') => void;
  onClose: () => void;
}

type HandState = 'fist' | 'open' | 'pointing' | 'neutral';

export const GestureController: React.FC<GestureControllerProps> = ({ onControl, onClose }) => {
  const videoRef = useRef<HTMLVideoElement>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const [loading, setLoading] = useState(true);
  const [permissionError, setPermissionError] = useState(false);
  const [isExpanded, setIsExpanded] = useState(false); // Default to hidden (stealth mode)
  const landmarkerRef = useRef<HandLandmarker | null>(null);
  const requestRef = useRef<number>(0);

  // Track current state for visualization
  const [currentGesture, setCurrentGesture] = useState<HandState>('neutral');

  // Initialize MediaPipe HandLandmarker
  useEffect(() => {
    const init = async () => {
      try {
        const vision = await FilesetResolver.forVisionTasks(
          "https://cdn.jsdelivr.net/npm/@mediapipe/tasks-vision@0.10.8/wasm"
        );

        landmarkerRef.current = await HandLandmarker.createFromOptions(vision, {
          baseOptions: {
            modelAssetPath: `https://storage.googleapis.com/mediapipe-models/hand_landmarker/hand_landmarker/float16/1/hand_landmarker.task`,
            delegate: "GPU"
          },
          runningMode: "VIDEO",
          numHands: 1
        });

        startWebcam();
      } catch (error) {
        console.error("Error initializing MediaPipe:", error);
        setLoading(false);
      }
    };
    init();

    return () => {
      if (requestRef.current) cancelAnimationFrame(requestRef.current);
      if (videoRef.current && videoRef.current.srcObject) {
        const tracks = (videoRef.current.srcObject as MediaStream).getTracks();
        tracks.forEach(t => t.stop());
      }
    };
  }, []);

  const startWebcam = async () => {
    if (!videoRef.current) return;
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ video: { width: 320, height: 240 } });
      videoRef.current.srcObject = stream;
      videoRef.current.addEventListener('loadeddata', predictWebcam);
      setLoading(false);
    } catch (err) {
      console.error("Webcam error:", err);
      setPermissionError(true);
      setLoading(false);
    }
  };

  const detectHandState = (landmarks: any[]): HandState => {
    if (!landmarks || landmarks.length === 0) return 'neutral';

    const wrist = landmarks[0];
    const middleMCP = landmarks[9]; // Middle finger knuckle

    // Calculate scale reference (Wrist to Knuckle distance)
    const scale = Math.hypot(middleMCP.x - wrist.x, middleMCP.y - wrist.y);

    if (scale === 0) return 'neutral';

    // Check extended status of 4 fingers (Index to Pinky)
    // Indices: Index(8), Middle(12), Ring(16), Pinky(20)
    // Corresponding PIP joints: 6, 10, 14, 18
    const fingers = [
        { tip: 8, pip: 6 },
        { tip: 12, pip: 10 },
        { tip: 16, pip: 14 },
        { tip: 20, pip: 18 }
    ];

    let extendedCount = 0;

    fingers.forEach(({ tip: tipIdx, pip: pipIdx }) => {
      const tip = landmarks[tipIdx];
      const pip = landmarks[pipIdx];

      const dTip = Math.hypot(tip.x - wrist.x, tip.y - wrist.y);
      const dPip = Math.hypot(pip.x - wrist.x, pip.y - wrist.y);

      // If tip is further from wrist than PIP by a margin, consider extended
      if (dTip > dPip * 1.1) {
          extendedCount++;
      }
    });

    // Determine state
    // Open: 4 or 5 fingers extended (Thumb is variable, so we focus on 4 main fingers)
    if (extendedCount >= 4) return 'open';

    // Fist: 0 fingers extended
    if (extendedCount === 0) return 'fist';

    // Pointing / Two Fingers: 1 or 2 fingers extended
    // Usually Index (1) or Index+Middle (2)
    if (extendedCount === 1 || extendedCount === 2) return 'pointing';

    return 'neutral';
  };

  const predictWebcam = () => {
    if (!landmarkerRef.current || !videoRef.current || !canvasRef.current) return;

    // Safety check for video readiness
    if (videoRef.current.videoWidth === 0 || videoRef.current.videoHeight === 0) {
        requestRef.current = requestAnimationFrame(predictWebcam);
        return;
    }

    const startTimeMs = performance.now();
    const result = landmarkerRef.current.detectForVideo(videoRef.current, startTimeMs);

    let gesture: HandState = 'neutral';
    if (result.landmarks && result.landmarks.length > 0) {
        gesture = detectHandState(result.landmarks[0]);
    }

    // Process logic
    processGestures(result, gesture);

    // Draw UI
    draw(result, gesture);

    requestRef.current = requestAnimationFrame(predictWebcam);
  };

  const processGestures = (result: HandLandmarkerResult, gesture: HandState) => {
    if (result.landmarks && result.landmarks.length > 0) {
      const landmarks = result.landmarks[0];

      // Use Index Finger Tip (8) for cursor position tracking
      // This works well for both Pointing and Open Palm
      const cursor = landmarks[8];

      const x = cursor.x; // 0 (Left) -> 1 (Right)
      const y = cursor.y; // 0 (Top) -> 1 (Bottom)

      let dx = 0;
      let dy = 0;

      // Deadzone logic (Center 30% is safe)
      const DEADZONE = 0.15;
      const CENTER_X = 0.5;
      const CENTER_Y = 0.5;

      // 1. ZOOM IN: OPEN PALM
      if (gesture === 'open') {
        onControl(0, 1.0, 'zoom'); // POSITIVE for Expand/In
        return;
      } 

      // 2. ZOOM OUT: FIST
      if (gesture === 'fist') {
        onControl(0, -1.0, 'zoom'); // NEGATIVE for Contract/Out
        return;
      }

      // 3. ROTATE/MOVE: POINTING / TWO FINGERS / NEUTRAL
      // "Two fingers move in corresponding direction"

      // --- X Control (Rotation / Pan) ---
      if (x < CENTER_X - DEADZONE) {
        dx = (x - (CENTER_X - DEADZONE)) * 4; 
      } else if (x > CENTER_X + DEADZONE) {
        dx = (x - (CENTER_X + DEADZONE)) * 4;
      }

      // --- Y Control (Tilt) ---
      if (y < CENTER_Y - DEADZONE) {
         dy = (y - (CENTER_Y - DEADZONE)) * 2; 
      } else if (y > CENTER_Y + DEADZONE) {
         dy = (y - (CENTER_Y + DEADZONE)) * 2;
      }

      onControl(dx, dy, 'rotate');
    } else {
        // No hand -> No movement
        onControl(0, 0, 'rotate');
    }
  };

  const draw = (result: HandLandmarkerResult, gesture: HandState) => {
    const canvas = canvasRef.current;
    if (!canvas) return;

    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    ctx.clearRect(0, 0, canvas.width, canvas.height);

    // Draw semi-transparent overlay
    ctx.fillStyle = 'rgba(0, 0, 0, 0.2)';
    ctx.fillRect(0, 0, canvas.width, canvas.height);

    // Draw Guide Box
    const w = canvas.width;
    const h = canvas.height;
    const zoneW = w * 0.3;
    const zoneH = h * 0.3;
    const zoneX = (w - zoneW) / 2;
    const zoneY = (h - zoneH) / 2;

    // Set Colors based on Gesture
    let mainColor = 'rgba(255, 255, 255, 0.5)';
    let statusText = "";

    if (gesture === 'open') {
        mainColor = '#00FF00'; // Green
        statusText = "🖐 放大 (ZOOM IN)";
    } else if (gesture === 'fist') {
        mainColor = '#FF0055'; // Red
        statusText = "✊ 缩小 (ZOOM OUT)";
    } else if (gesture === 'pointing') {
        mainColor = '#FFFF00'; // Yellow
        statusText = "✌️ 移动 (MOVE)";
    } else {
        mainColor = 'rgba(255, 255, 255, 0.5)';
        statusText = "等待手势...";
    }

    ctx.strokeStyle = mainColor;
    ctx.lineWidth = 3;
    ctx.setLineDash([5, 5]);
    ctx.strokeRect(zoneX, zoneY, zoneW, zoneH);
    ctx.setLineDash([]);

    // Status Text
    if (statusText) {
        ctx.font = "bold 16px 'ZCOOL KuaiLe', sans-serif";
        ctx.fillStyle = mainColor;
        ctx.shadowColor = "rgba(0,0,0,0.8)";
        ctx.shadowBlur = 4;
        ctx.fillText(statusText, 10, 25);
        ctx.shadowBlur = 0;
    }

    // Center Crosshair
    ctx.fillStyle = 'rgba(255, 255, 255, 0.3)';
    ctx.fillRect(w/2 - 1, h/2 - 5, 2, 10);
    ctx.fillRect(w/2 - 5, h/2 - 1, 10, 2);

    if (result.landmarks) {
      for (const landmarks of result.landmarks) {
        drawConnectors(ctx, landmarks, HandLandmarker.HAND_CONNECTIONS, { color: "rgba(255,255,255,0.3)", lineWidth: 2 });
        drawLandmarks(ctx, landmarks, { color: mainColor, lineWidth: 2, radius: 4 });

        // Highlight Cursor (Index Tip)
        const index = landmarks[8];
        ctx.beginPath();
        ctx.arc(index.x * w, index.y * h, 10, 0, 2 * Math.PI);
        ctx.fillStyle = mainColor;
        ctx.fill();
        ctx.strokeStyle = "#FFFFFF";
        ctx.lineWidth = 2;
        ctx.stroke();
      }
    }
  };

  const drawConnectors = (ctx: CanvasRenderingContext2D, landmarks: any[], connections: any[], style: any) => {
      ctx.strokeStyle = style.color;
      ctx.lineWidth = style.lineWidth;
      for (const conn of connections) {
          const start = landmarks[conn.start];
          const end = landmarks[conn.end];
          if (start && end) {
            ctx.beginPath();
            ctx.moveTo(start.x * canvasRef.current!.width, start.y * canvasRef.current!.height);
            ctx.lineTo(end.x * canvasRef.current!.width, end.y * canvasRef.current!.height);
            ctx.stroke();
          }
      }
  };

  const drawLandmarks = (ctx: CanvasRenderingContext2D, landmarks: any[], style: any) => {
      ctx.fillStyle = style.color;
      for (const lm of landmarks) {
          ctx.beginPath();
          ctx.arc(lm.x * canvasRef.current!.width, lm.y * canvasRef.current!.height, style.radius, 0, 2 * Math.PI);
          ctx.fill();
      }
  };

  return (
    <div className="absolute bottom-4 right-4 z-50 flex flex-col items-end gap-3 animate-fade-in pointer-events-auto">

      {/* Camera Feed Container */}
      <div className={`relative rounded-2xl overflow-hidden border-4 border-yellow-400 shadow-[0_0_20px_rgba(255,215,0,0.5)] bg-black transition-all duration-300 ease-in-out origin-bottom-right ${
          isExpanded 
            ? 'w-[240px] h-[180px] opacity-100 scale-100 mb-2' 
            : 'w-[200px] h-[150px] opacity-0 scale-50 absolute bottom-0 right-0 -z-50 pointer-events-none'
        }`}>
        <video 
            ref={videoRef} 
            className="w-full h-full object-cover -scale-x-100" 
            autoPlay 
            playsInline 
            muted
        />
        <canvas 
            ref={canvasRef} 
            width={240}
            height={180}
            className="absolute top-0 left-0 w-full h-full -scale-x-100" 
        />

        {permissionError && (
          <div className="absolute inset-0 bg-black/90 flex items-center justify-center p-4 text-center z-10">
             <div className="text-red-400 font-bold text-xs">
                无法访问摄像头<br/>请检查权限设置
             </div>
          </div>
        )}
      </div>

      {/* Control Bar */}
      <div className="flex items-center gap-3">
         {/* Status Pill */}
         <div className="bg-black/80 backdrop-blur-md text-white pl-4 pr-1 py-1.5 rounded-full border border-green-500/30 shadow-lg flex items-center gap-3">
            <div className="flex items-center gap-2">
               {/* Status Dot */}
               <span className={`w-2 h-2 rounded-full ${loading ? 'bg-yellow-400 animate-ping' : 'bg-green-500 animate-pulse'}`}></span>
               <span className="text-xs font-bold font-mono text-green-400 tracking-wide">
                 {loading ? "正在启动..." : "魔法手势 ON"}
               </span>
            </div>

            {/* Show/Hide Camera Toggle */}
            <button 
              onClick={() => setIsExpanded(!isExpanded)}
              className="bg-gray-800 hover:bg-gray-700 text-gray-300 hover:text-white px-3 py-1 rounded-full text-[10px] font-bold transition-colors border border-gray-600 uppercase"
              title={isExpanded ? "隐藏摄像头" : "显示摄像头"}
            >
              {isExpanded ? "隐藏画面" : "显示画面"}
            </button>
         </div>

         {/* Close Button */}
         <button 
            onClick={onClose}
            className="w-10 h-10 bg-red-500 hover:bg-red-400 text-white rounded-full flex items-center justify-center shadow-lg border-2 border-white active:scale-95 transition-all"
            title="关闭手势控制"
         >
            <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3" strokeLinecap="round" strokeLinejoin="round">
               <line x1="18" y1="6" x2="6" y2="18"></line>
               <line x1="6" y1="6" x2="18" y2="18"></line>
            </svg>
         </button>
      </div>

    </div>
  );
};

import React, { useState, Suspense, useRef, useMemo, useEffect } from 'react';
import { Canvas, useFrame } from '@react-three/fiber';
import { OrbitControls, Sparkles, PerspectiveCamera, Environment, Stars } from '@react-three/drei';
import { Vector3, TextureLoader, BackSide, Mesh, Object3D, RepeatWrapping, ClampToEdgeWrapping } from 'three';
import { PLANETS, SUN_DATA } from './constants';
import { Planet } from './components/Planet';
import { Sun } from './components/Sun';
import { Starship } from './components/Starship';
import { AsteroidBelt } from './components/AsteroidBelt';
import { UIOverlay } from './components/UIOverlay';
import { GestureController } from './components/GestureController';
import { generateStarFieldTexture } from './utils/textureGenerator';

const Skybox: React.FC = () => {
  const meshRef = useRef<Mesh>(null);
  const starTextureUrl = useMemo(() => generateStarFieldTexture(), []);
  const starTexture = useMemo(() => {
    const t = new TextureLoader().load(starTextureUrl);
    // Important: Use RepeatWrapping to ensure seamless UV wrapping, 
    // although our content is manually wrapped, this helps with interpolation at the seam.
    t.wrapS = RepeatWrapping;
    t.wrapT = ClampToEdgeWrapping; // Vertical poles clamp
    return t;
  }, [starTextureUrl]);

  useFrame((state, delta) => {
    if (meshRef.current) {
      meshRef.current.rotation.y += delta * 0.0002; // Reduced from 0.0005
    }
  });

  return (
    <mesh ref={meshRef}>
      {/* Increased radius to ensure it encompasses the 3D Stars volume */}
      <sphereGeometry args={[500, 64, 64]} />
      <meshBasicMaterial 
        map={starTexture} 
        side={BackSide} 
        color="#ffffff"
      />
    </mesh>
  );
};

// Component to handle applying gesture inputs to OrbitControls
const OrbitController = ({ controlsRef, gestureVelocity }: { controlsRef: any, gestureVelocity: React.MutableRefObject<{dx: number, dy: number, gestureType: 'rotate' | 'zoom'}> }) => {
  useFrame(() => {
    if (controlsRef.current && controlsRef.current.enabled) {
      const { dx, dy, gestureType } = gestureVelocity.current;

      const threshold = 0.01;
      const isActive = Math.abs(dx) > threshold || Math.abs(dy) > threshold;

      if (isActive) {
          if (gestureType === 'rotate') {
             // ROTATE MODE
             // dx negative (Hand Left) -> rotate left -> map moves left.
             controlsRef.current.setAzimuthalAngle(controlsRef.current.getAzimuthalAngle() + dx * 0.05);

             // dy negative (Hand Up) -> Drag Map Up -> Camera looks down -> Angle Increase
             // dy positive (Hand Down) -> Drag Map Down -> Camera looks up -> Angle Decrease
             // We subtract dy to match "Drag" feel.
             controlsRef.current.setPolarAngle(controlsRef.current.getPolarAngle() - dy * 0.05);
          } else if (gestureType === 'zoom') {
             // ZOOM MODE (Pinch/Fist/Palm)
             // dy positive (Open Palm/Expand) -> Zoom In (dollyIn)
             // dy negative (Fist/Contract) -> Zoom Out (dollyOut)
             const zoomSpeed = 0.05;
             const zoomFactor = 1.0 + Math.abs(dy) * zoomSpeed;

             if (dy > 0) {
                 controlsRef.current.dollyIn(zoomFactor);
             } else {
                 controlsRef.current.dollyOut(zoomFactor);
             }
          }
          controlsRef.current.update();
      }
    }
  });
  return null;
}

const App: React.FC = () => {
  const [selectedPlanetId, setSelectedPlanetId] = useState<string | null>(null);
  const [isPaused, setIsPaused] = useState(false);
  const [simulationSpeed, setSimulationSpeed] = useState(1.0); // Default speed 1x
  const [isStarshipActive, setIsStarshipActive] = useState(false);
  const [showPluto, setShowPluto] = useState(false);
  const [isGestureMode, setIsGestureMode] = useState(false);

  const earthPositionRef = useRef<Vector3>(new Vector3(0, 0, 0));
  const planetRefs = useRef<{ [key: string]: Object3D }>({});
  const controlsRef = useRef<any>(null);

  // Ref to store current gesture velocity to avoid re-renders on every frame update
  const gestureVelocity = useRef<{dx: number, dy: number, gestureType: 'rotate' | 'zoom'}>({ dx: 0, dy: 0, gestureType: 'rotate' });

  const handleSelect = (id: string) => {
    setSelectedPlanetId(id);
    setIsPaused(true); // Stop orbit when a planet is selected
  };

  const handleClose = () => {
    setSelectedPlanetId(null);
    setIsPaused(false); // Resume orbit when closed
  };

  const togglePluto = () => {
    const newValue = !showPluto;
    setShowPluto(newValue);
    // If we are hiding Pluto and it is currently selected, deselect it
    if (!newValue && selectedPlanetId === 'pluto') {
      handleClose();
    }
  };

  const handleGestureControl = (dx: number, dy: number, gestureType: 'rotate' | 'zoom') => {
    gestureVelocity.current = { dx, dy, gestureType };
  };

  const toggleGestureMode = () => {
    const nextState = !isGestureMode;
    setIsGestureMode(nextState);
    if (nextState) {
      setSimulationSpeed(1.0);
    }
  };

  // Find the selected planet object (Sun or normal Planet)
  const selectedPlanet = useMemo(() => {
    if (selectedPlanetId === 'sun') return SUN_DATA;
    return PLANETS.find(p => p.id === selectedPlanetId) || null;
  }, [selectedPlanetId]);

  // Filter planets based on showPluto state
  const displayedPlanets = useMemo(() => {
    return showPluto ? PLANETS : PLANETS.filter(p => p.id !== 'pluto');
  }, [showPluto]);

  return (
    <div className="w-full h-screen bg-black relative overflow-hidden">

      <UIOverlay 
        selectedPlanet={selectedPlanet}
        onClose={handleClose}
        isPaused={isPaused}
        togglePause={() => setIsPaused(!isPaused)}
        simulationSpeed={simulationSpeed}
        setSimulationSpeed={setSimulationSpeed}
        isStarshipActive={isStarshipActive}
        toggleStarship={() => setIsStarshipActive(!isStarshipActive)}
        showPluto={showPluto}
        togglePluto={togglePluto}
        isGestureMode={isGestureMode}
        toggleGestureMode={toggleGestureMode}
      />

      {isGestureMode && (
        <GestureController 
          onControl={handleGestureControl} 
          onClose={() => setIsGestureMode(false)} 
        />
      )}

      <Canvas gl={{ antialias: true, toneMappingExposure: 1.2 }}>
        <Suspense fallback={null}>
          <PerspectiveCamera makeDefault position={[0, 80, 120]} fov={45} />

          <OrbitControls 
            ref={controlsRef}
            makeDefault
            enabled={!isStarshipActive} // Disable manual control when starship is active
            enableDamping={true}
            dampingFactor={0.05}
            enablePan={false}
            minDistance={20}
            maxDistance={300}
            maxPolarAngle={Math.PI / 1.8}
            autoRotate={!selectedPlanetId && !isPaused && !isGestureMode && !isStarshipActive}
            autoRotateSpeed={0.15 * simulationSpeed}
          />

          <OrbitController controlsRef={controlsRef} gestureVelocity={gestureVelocity} />

          <Environment preset="city" environmentIntensity={0.3} />
          <pointLight position={[0, 0, 0]} intensity={2.5} distance={500} decay={1} color="#FFF5E0" />
          <ambientLight intensity={0.15} color="#404060" />

          {/* 1. Volumetric 3D Stars (Mid-distance) */}
          <Stars radius={400} depth={50} count={3000} factor={4} saturation={0.5} fade speed={0.5} />

          {/* 2. Painted Background (Infinite Distance) */}
          <Skybox />

          {/* 3. Magical Dust (Near-distance) */}
          <Sparkles count={400} scale={200} size={6} speed={0.2} opacity={0.4} noise={0.1} color="#88AAFF" />
          <Sparkles count={150} scale={150} size={3} speed={0.3} opacity={0.6} color="#FFD700" />

          <Sun 
             onSelect={handleSelect}
             isSelected={selectedPlanetId === 'sun'}
             isPaused={isPaused}
             simulationSpeed={simulationSpeed}
          />

          {/* Asteroid Belt located between Mars and Jupiter */}
          <AsteroidBelt isPaused={isPaused} simulationSpeed={simulationSpeed} />

          {displayedPlanets.map((planet) => (
            <Planet 
              key={planet.id} 
              data={planet} 
              isSelected={selectedPlanetId === planet.id}
              onSelect={handleSelect}
              isPaused={isPaused}
              simulationSpeed={simulationSpeed}
              earthPositionRef={earthPositionRef}
              planetRefs={planetRefs}
            />
          ))}

          {isStarshipActive && <Starship planetRefs={planetRefs} />}

        </Suspense>
      </Canvas>
    </div>
  );
};

export default App;

import React, { useEffect, useRef, useState } from 'react';
import { FilesetResolver, HandLandmarker, HandLandmarkerResult } from '@mediapipe/tasks-vision';

interface GestureControllerProps {
  onControl: (dx: number, dy: number, gestureType: 'rotate' | 'zoom') => void;
  onClose: () => void;
}

type HandState = 'fist' | 'open' | 'pointing' | 'neutral';

export const GestureController: React.FC<GestureControllerProps> = ({ onControl, onClose }) => {
  const videoRef = useRef<HTMLVideoElement>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const [loading, setLoading] = useState(true);
  const [permissionError, setPermissionError] = useState(false);
  const [isExpanded, setIsExpanded] = useState(false); // Default to hidden (stealth mode)
  const landmarkerRef = useRef<HandLandmarker | null>(null);
  const requestRef = useRef<number>(0);

  // Track current state for visualization
  const [currentGesture, setCurrentGesture] = useState<HandState>('neutral');

  // Initialize MediaPipe HandLandmarker
  useEffect(() => {
    let isMounted = true;

    const init = async () => {
      try {
        const vision = await FilesetResolver.forVisionTasks(
          "https://cdn.jsdelivr.net/npm/@mediapipe/tasks-vision@0.10.8/wasm"
        );

        if (!isMounted) return;

        landmarkerRef.current = await HandLandmarker.createFromOptions(vision, {
          baseOptions: {
            modelAssetPath: `https://storage.googleapis.com/mediapipe-models/hand_landmarker/hand_landmarker/float16/1/hand_landmarker.task`,
            delegate: "GPU"
          },
          runningMode: "VIDEO",
          numHands: 1
        });

        if (isMounted) {
            startWebcam();
        }
      } catch (error) {
        console.error("Error initializing MediaPipe:", error);
        if (isMounted) setLoading(false);
      }
    };
    init();

    return () => {
      isMounted = false;
      if (requestRef.current) cancelAnimationFrame(requestRef.current);
      if (videoRef.current && videoRef.current.srcObject) {
        const tracks = (videoRef.current.srcObject as MediaStream).getTracks();
        tracks.forEach(t => t.stop());
      }
    };
  }, []);

  const startWebcam = async () => {
    if (!videoRef.current) return;

    setLoading(true);
    setPermissionError(false);

    try {
      // Use relaxed constraints to ensure it works on more devices
      // We try to request a sensible size, but don't fail if exact size isn't met
      const constraints = { 
        video: { 
            width: { ideal: 320 }, 
            height: { ideal: 240 },
            facingMode: 'user'
        } 
      };

      const stream = await navigator.mediaDevices.getUserMedia(constraints);

      if (videoRef.current) {
          videoRef.current.srcObject = stream;
          // Explicitly play to ensure video stream starts
          await videoRef.current.play();

          // Only start prediction loop once data is actually flowing
          videoRef.current.addEventListener('loadeddata', () => {
              predictWebcam();
              setLoading(false);
          });
      }
    } catch (err) {
      console.error("Webcam error:", err);
      setPermissionError(true);
      setLoading(false);
    }
  };

  const detectHandState = (landmarks: any[]): HandState => {
    if (!landmarks || landmarks.length === 0) return 'neutral';

    const wrist = landmarks[0];
    const middleMCP = landmarks[9]; // Middle finger knuckle

    // Calculate scale reference (Wrist to Knuckle distance)
    const scale = Math.hypot(middleMCP.x - wrist.x, middleMCP.y - wrist.y);

    if (scale === 0) return 'neutral';

    // Check extended status of 4 fingers (Index to Pinky)
    // Indices: Index(8), Middle(12), Ring(16), Pinky(20)
    // Corresponding PIP joints: 6, 10, 14, 18
    const fingers = [
        { tip: 8, pip: 6 },
        { tip: 12, pip: 10 },
        { tip: 16, pip: 14 },
        { tip: 20, pip: 18 }
    ];

    let extendedCount = 0;

    fingers.forEach(({ tip: tipIdx, pip: pipIdx }) => {
      const tip = landmarks[tipIdx];
      const pip = landmarks[pipIdx];

      const dTip = Math.hypot(tip.x - wrist.x, tip.y - wrist.y);
      const dPip = Math.hypot(pip.x - wrist.x, pip.y - wrist.y);

      // If tip is further from wrist than PIP by a margin, consider extended
      if (dTip > dPip * 1.1) {
          extendedCount++;
      }
    });

    // Determine state
    // Open: 4 or 5 fingers extended (Thumb is variable, so we focus on 4 main fingers)
    if (extendedCount >= 4) return 'open';

    // Fist: 0 fingers extended
    if (extendedCount === 0) return 'fist';

    // Pointing / Two Fingers: 1 or 2 fingers extended
    // Usually Index (1) or Index+Middle (2)
    if (extendedCount === 1 || extendedCount === 2) return 'pointing';

    return 'neutral';
  };

  const predictWebcam = () => {
    if (!landmarkerRef.current || !videoRef.current || !canvasRef.current) return;

    // Safety check for video readiness
    if (videoRef.current.videoWidth === 0 || videoRef.current.videoHeight === 0) {
        requestRef.current = requestAnimationFrame(predictWebcam);
        return;
    }

    const startTimeMs = performance.now();
    let result: HandLandmarkerResult | null = null;
    try {
        result = landmarkerRef.current.detectForVideo(videoRef.current, startTimeMs);
    } catch (e) {
        console.warn("Detection error", e);
    }

    let gesture: HandState = 'neutral';
    if (result && result.landmarks && result.landmarks.length > 0) {
        gesture = detectHandState(result.landmarks[0]);
    }

    // Process logic
    if (result) {
        processGestures(result, gesture);
        // Draw UI
        draw(result, gesture);
    }

    requestRef.current = requestAnimationFrame(predictWebcam);
  };

  const processGestures = (result: HandLandmarkerResult, gesture: HandState) => {
    if (result.landmarks && result.landmarks.length > 0) {
      const landmarks = result.landmarks[0];

      // Use Index Finger Tip (8) for cursor position tracking
      // This works well for both Pointing and Open Palm
      const cursor = landmarks[8];

      const x = cursor.x; // 0 (Left) -> 1 (Right)
      const y = cursor.y; // 0 (Top) -> 1 (Bottom)

      let dx = 0;
      let dy = 0;

      // Deadzone logic (Center 30% is safe)
      const DEADZONE = 0.15;
      const CENTER_X = 0.5;
      const CENTER_Y = 0.5;

      // 1. ZOOM IN: OPEN PALM
      if (gesture === 'open') {
        onControl(0, 1.0, 'zoom'); // POSITIVE for Expand/In
        return;
      } 

      // 2. ZOOM OUT: FIST
      if (gesture === 'fist') {
        onControl(0, -1.0, 'zoom'); // NEGATIVE for Contract/Out
        return;
      }

      // 3. ROTATE/MOVE: POINTING / TWO FINGERS / NEUTRAL
      // "Two fingers move in corresponding direction"

      // --- X Control (Rotation / Pan) ---
      if (x < CENTER_X - DEADZONE) {
        dx = (x - (CENTER_X - DEADZONE)) * 4; 
      } else if (x > CENTER_X + DEADZONE) {
        dx = (x - (CENTER_X + DEADZONE)) * 4;
      }

      // --- Y Control (Tilt) ---
      if (y < CENTER_Y - DEADZONE) {
         dy = (y - (CENTER_Y - DEADZONE)) * 2; 
      } else if (y > CENTER_Y + DEADZONE) {
         dy = (y - (CENTER_Y + DEADZONE)) * 2;
      }

      onControl(dx, dy, 'rotate');
    } else {
        // No hand -> No movement
        onControl(0, 0, 'rotate');
    }
  };

  const draw = (result: HandLandmarkerResult, gesture: HandState) => {
    const canvas = canvasRef.current;
    if (!canvas) return;

    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    ctx.clearRect(0, 0, canvas.width, canvas.height);

    // Draw semi-transparent overlay
    ctx.fillStyle = 'rgba(0, 0, 0, 0.2)';
    ctx.fillRect(0, 0, canvas.width, canvas.height);

    // Draw Guide Box
    const w = canvas.width;
    const h = canvas.height;
    const zoneW = w * 0.3;
    const zoneH = h * 0.3;
    const zoneX = (w - zoneW) / 2;
    const zoneY = (h - zoneH) / 2;

    // Set Colors based on Gesture
    let mainColor = 'rgba(255, 255, 255, 0.5)';
    let statusText = "";

    if (gesture === 'open') {
        mainColor = '#00FF00'; // Green
        statusText = "🖐 放大 (ZOOM IN)";
    } else if (gesture === 'fist') {
        mainColor = '#FF0055'; // Red
        statusText = "✊ 缩小 (ZOOM OUT)";
    } else if (gesture === 'pointing') {
        mainColor = '#FFFF00'; // Yellow
        statusText = "✌️ 移动 (MOVE)";
    } else {
        mainColor = 'rgba(255, 255, 255, 0.5)';
        statusText = "等待手势...";
    }

    ctx.strokeStyle = mainColor;
    ctx.lineWidth = 3;
    ctx.setLineDash([5, 5]);
    ctx.strokeRect(zoneX, zoneY, zoneW, zoneH);
    ctx.setLineDash([]);

    // Status Text
    if (statusText) {
        ctx.font = "bold 16px 'ZCOOL KuaiLe', sans-serif";
        ctx.fillStyle = mainColor;
        ctx.shadowColor = "rgba(0,0,0,0.8)";
        ctx.shadowBlur = 4;
        ctx.fillText(statusText, 10, 25);
        ctx.shadowBlur = 0;
    }

    // Center Crosshair
    ctx.fillStyle = 'rgba(255, 255, 255, 0.3)';
    ctx.fillRect(w/2 - 1, h/2 - 5, 2, 10);
    ctx.fillRect(w/2 - 5, h/2 - 1, 10, 2);

    if (result.landmarks) {
      for (const landmarks of result.landmarks) {
        drawConnectors(ctx, landmarks, HandLandmarker.HAND_CONNECTIONS, { color: "rgba(255,255,255,0.3)", lineWidth: 2 });
        drawLandmarks(ctx, landmarks, { color: mainColor, lineWidth: 2, radius: 4 });

        // Highlight Cursor (Index Tip)
        const index = landmarks[8];
        ctx.beginPath();
        ctx.arc(index.x * w, index.y * h, 10, 0, 2 * Math.PI);
        ctx.fillStyle = mainColor;
        ctx.fill();
        ctx.strokeStyle = "#FFFFFF";
        ctx.lineWidth = 2;
        ctx.stroke();
      }
    }
  };

  const drawConnectors = (ctx: CanvasRenderingContext2D, landmarks: any[], connections: any[], style: any) => {
      ctx.strokeStyle = style.color;
      ctx.lineWidth = style.lineWidth;
      for (const conn of connections) {
          const start = landmarks[conn.start];
          const end = landmarks[conn.end];
          if (start && end) {
            ctx.beginPath();
            ctx.moveTo(start.x * canvasRef.current!.width, start.y * canvasRef.current!.height);
            ctx.lineTo(end.x * canvasRef.current!.width, end.y * canvasRef.current!.height);
            ctx.stroke();
          }
      }
  };

  const drawLandmarks = (ctx: CanvasRenderingContext2D, landmarks: any[], style: any) => {
      ctx.fillStyle = style.color;
      for (const lm of landmarks) {
          ctx.beginPath();
          ctx.arc(lm.x * canvasRef.current!.width, lm.y * canvasRef.current!.height, style.radius, 0, 2 * Math.PI);
          ctx.fill();
      }
  };

  return (
    <div className="absolute bottom-4 right-4 z-50 flex flex-col items-end gap-3 animate-fade-in pointer-events-auto">

      {/* Camera Feed Container */}
      <div className={`relative rounded-2xl overflow-hidden border-4 border-yellow-400 shadow-[0_0_20px_rgba(255,215,0,0.5)] bg-black transition-all duration-300 ease-in-out origin-bottom-right ${
          isExpanded 
            ? 'w-[240px] h-[180px] opacity-100 scale-100 mb-2' 
            : 'w-[200px] h-[150px] opacity-0 scale-50 absolute bottom-0 right-0 -z-50 pointer-events-none'
        }`}>
        <video 
            ref={videoRef} 
            className="w-full h-full object-cover -scale-x-100" 
            autoPlay 
            playsInline 
            muted
        />
        <canvas 
            ref={canvasRef} 
            width={240}
            height={180}
            className="absolute top-0 left-0 w-full h-full -scale-x-100" 
        />

        {permissionError && (
          <div className="absolute inset-0 bg-black/90 flex flex-col items-center justify-center p-4 text-center z-10 gap-2">
             <div className="text-red-400 font-bold text-xs">
                无法访问摄像头<br/>请检查权限设置
             </div>
             <button 
               onClick={() => startWebcam()}
               className="bg-red-500 hover:bg-red-600 text-white text-[10px] px-3 py-1 rounded-full border border-red-400"
             >
               重试
             </button>
          </div>
        )}
      </div>

      {/* Control Bar */}
      <div className="flex items-center gap-3">
         {/* Status Pill */}
         <div className="bg-black/80 backdrop-blur-md text-white pl-4 pr-1 py-1.5 rounded-full border border-green-500/30 shadow-lg flex items-center gap-3">
            <div className="flex items-center gap-2">
               {/* Status Dot */}
               <span className={`w-2 h-2 rounded-full ${loading ? 'bg-yellow-400 animate-ping' : 'bg-green-500 animate-pulse'}`}></span>
               <span className="text-xs font-bold font-mono text-green-400 tracking-wide">
                 {loading ? "正在启动..." : "魔法手势 ON"}
               </span>
            </div>

            {/* Show/Hide Camera Toggle */}
            <button 
              onClick={() => setIsExpanded(!isExpanded)}
              className="bg-gray-800 hover:bg-gray-700 text-gray-300 hover:text-white px-3 py-1 rounded-full text-[10px] font-bold transition-colors border border-gray-600 uppercase"
              title={isExpanded ? "隐藏摄像头" : "显示摄像头"}
            >
              {isExpanded ? "隐藏画面" : "显示画面"}
            </button>
         </div>

         {/* Close Button */}
         <button 
            onClick={onClose}
            className="w-10 h-10 bg-red-500 hover:bg-red-400 text-white rounded-full flex items-center justify-center shadow-lg border-2 border-white active:scale-95 transition-all"
            title="关闭手势控制"
         >
            <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3" strokeLinecap="round" strokeLinejoin="round">
               <line x1="18" y1="6" x2="6" y2="18"></line>
               <line x1="6" y1="6" x2="18" y2="18"></line>
            </svg>
         </button>
      </div>

    </div>
  );
};

