import React, { useEffect, useRef, useState } from 'react';
import { FilesetResolver, HandLandmarker, HandLandmarkerResult } from '@mediapipe/tasks-vision';

interface GestureControllerProps {
  onControl: (dx: number, dy: number, gestureType: 'rotate' | 'zoom') => void;
  onClose: () => void;
}

type HandState = 'fist' | 'open' | 'pointing' | 'neutral';

export const GestureController: React.FC<GestureControllerProps> = ({ onControl, onClose }) => {
  const videoRef = useRef<HTMLVideoElement>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);

  const [loading, setLoading] = useState(true);
  const [loadingStatus, setLoadingStatus] = useState("正在启动..."); // Detailed status text
  const [permissionError, setPermissionError] = useState(false);
  const [isExpanded, setIsExpanded] = useState(false); // Default to hidden (stealth mode)

  const landmarkerRef = useRef<HandLandmarker | null>(null);
  const requestRef = useRef<number>(0);
  const isLoopRunning = useRef(false);

  // Initialize MediaPipe HandLandmarker
  useEffect(() => {
    let isMounted = true;

    const init = async () => {
      setLoadingStatus("加载AI模型...");
      try {
        const vision = await FilesetResolver.forVisionTasks(
          "https://cdn.jsdelivr.net/npm/@mediapipe/tasks-vision@0.10.8/wasm"
        );

        if (!isMounted) return;

        landmarkerRef.current = await HandLandmarker.createFromOptions(vision, {
          baseOptions: {
            modelAssetPath: `https://storage.googleapis.com/mediapipe-models/hand_landmarker/hand_landmarker/float16/1/hand_landmarker.task`,
            delegate: "GPU"
          },
          runningMode: "VIDEO",
          numHands: 1
        });

        if (isMounted) {
            startWebcam();
        }
      } catch (error) {
        console.error("Error initializing MediaPipe:", error);
        if (isMounted) {
            setPermissionError(true); 
            setLoading(false);
        }
      }
    };
    init();

    return () => {
      isMounted = false;
      stopLoop();
      if (videoRef.current && videoRef.current.srcObject) {
        const tracks = (videoRef.current.srcObject as MediaStream).getTracks();
        tracks.forEach(t => t.stop());
      }
    };
  }, []);

  const stopLoop = () => {
    if (requestRef.current) {
        cancelAnimationFrame(requestRef.current);
        requestRef.current = 0;
    }
    isLoopRunning.current = false;
  };

  const startWebcam = async () => {
    if (!videoRef.current) return;

    setLoading(true);
    setLoadingStatus("打开摄像头...");
    setPermissionError(false);

    try {
      // Use relaxed constraints to ensure it works on more devices
      const constraints = { 
        video: { 
            width: { ideal: 320 }, 
            height: { ideal: 240 },
            facingMode: 'user'
        } 
      };

      const stream = await navigator.mediaDevices.getUserMedia(constraints);

      if (videoRef.current) {
          videoRef.current.srcObject = stream;

          // Function to safely start the loop only once
          const beginPrediction = () => {
              if (isLoopRunning.current) return;
              setLoading(false);
              predictWebcam();
          };

          // 1. Check if ready immediately
          if (videoRef.current.readyState >= 2) { // HAVE_CURRENT_DATA
             beginPrediction();
          } else {
             // 2. Listen for loadeddata
             videoRef.current.onloadeddata = () => {
                 beginPrediction();
             };
          }

          // 3. Fallback Safety Timeout (3 seconds)
          // If event listeners fail, force start to avoid "Always Starting"
          setTimeout(() => {
             if (loading) {
                 console.log("Force starting prediction loop...");
                 beginPrediction();
             }
          }, 3000);

          await videoRef.current.play();
      }
    } catch (err) {
      console.error("Webcam error:", err);
      setPermissionError(true);
      setLoading(false);
    }
  };

  const detectHandState = (landmarks: any[]): HandState => {
    if (!landmarks || landmarks.length === 0) return 'neutral';

    const wrist = landmarks[0];
    const middleMCP = landmarks[9]; // Middle finger knuckle

    // Calculate scale reference (Wrist to Knuckle distance)
    const scale = Math.hypot(middleMCP.x - wrist.x, middleMCP.y - wrist.y);

    if (scale === 0) return 'neutral';

    // Check extended status of 4 fingers (Index to Pinky)
    const fingers = [
        { tip: 8, pip: 6 },
        { tip: 12, pip: 10 },
        { tip: 16, pip: 14 },
        { tip: 20, pip: 18 }
    ];

    let extendedCount = 0;

    fingers.forEach(({ tip: tipIdx, pip: pipIdx }) => {
      const tip = landmarks[tipIdx];
      const pip = landmarks[pipIdx];
      const dTip = Math.hypot(tip.x - wrist.x, tip.y - wrist.y);
      const dPip = Math.hypot(pip.x - wrist.x, pip.y - wrist.y);
      if (dTip > dPip * 1.1) extendedCount++;
    });

    // Determine state
    if (extendedCount >= 4) return 'open';
    if (extendedCount === 0) return 'fist';
    if (extendedCount === 1 || extendedCount === 2) return 'pointing';

    return 'neutral';
  };

  const predictWebcam = () => {
    // Flag to prevent multiple loops
    isLoopRunning.current = true;

    if (!landmarkerRef.current || !videoRef.current || !canvasRef.current) return;

    // Safety check for video readiness
    if (videoRef.current.videoWidth === 0 || videoRef.current.videoHeight === 0) {
        requestRef.current = requestAnimationFrame(predictWebcam);
        return;
    }

    const startTimeMs = performance.now();
    let result: HandLandmarkerResult | null = null;
    try {
        result = landmarkerRef.current.detectForVideo(videoRef.current, startTimeMs);
    } catch (e) {
        // console.warn("Detection error", e);
    }

    let gesture: HandState = 'neutral';
    if (result && result.landmarks && result.landmarks.length > 0) {
        gesture = detectHandState(result.landmarks[0]);
    }

    // Process logic
    if (result) {
        processGestures(result, gesture);
        draw(result, gesture);
    }

    requestRef.current = requestAnimationFrame(predictWebcam);
  };

  const processGestures = (result: HandLandmarkerResult, gesture: HandState) => {
    if (result.landmarks && result.landmarks.length > 0) {
      const landmarks = result.landmarks[0];
      const cursor = landmarks[8];

      const x = cursor.x; 
      const y = cursor.y; 

      let dx = 0;
      let dy = 0;

      const DEADZONE = 0.15;
      const CENTER_X = 0.5;
      const CENTER_Y = 0.5;

      // 1. ZOOM IN: OPEN PALM
      if (gesture === 'open') {
        onControl(0, 1.0, 'zoom'); // POSITIVE for Expand/In
        return;
      } 

      // 2. ZOOM OUT: FIST
      if (gesture === 'fist') {
        onControl(0, -1.0, 'zoom'); // NEGATIVE for Contract/Out
        return;
      }

      // 3. ROTATE/MOVE
      if (x < CENTER_X - DEADZONE) {
        dx = (x - (CENTER_X - DEADZONE)) * 4; 
      } else if (x > CENTER_X + DEADZONE) {
        dx = (x - (CENTER_X + DEADZONE)) * 4;
      }

      if (y < CENTER_Y - DEADZONE) {
         dy = (y - (CENTER_Y - DEADZONE)) * 2; 
      } else if (y > CENTER_Y + DEADZONE) {
         dy = (y - (CENTER_Y + DEADZONE)) * 2;
      }

      onControl(dx, dy, 'rotate');
    } else {
        onControl(0, 0, 'rotate');
    }
  };

  const draw = (result: HandLandmarkerResult, gesture: HandState) => {
    const canvas = canvasRef.current;
    if (!canvas) return;

    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    ctx.clearRect(0, 0, canvas.width, canvas.height);

    // Draw semi-transparent overlay
    ctx.fillStyle = 'rgba(0, 0, 0, 0.2)';
    ctx.fillRect(0, 0, canvas.width, canvas.height);

    // Draw Guide Box
    const w = canvas.width;
    const h = canvas.height;
    const zoneW = w * 0.3;
    const zoneH = h * 0.3;
    const zoneX = (w - zoneW) / 2;
    const zoneY = (h - zoneH) / 2;

    // Set Colors based on Gesture
    let mainColor = 'rgba(255, 255, 255, 0.5)';
    let statusText = "";

    if (gesture === 'open') {
        mainColor = '#00FF00'; // Green
        statusText = "🖐 放大 (ZOOM IN)";
    } else if (gesture === 'fist') {
        mainColor = '#FF0055'; // Red
        statusText = "✊ 缩小 (ZOOM OUT)";
    } else if (gesture === 'pointing') {
        mainColor = '#FFFF00'; // Yellow
        statusText = "✌️ 移动 (MOVE)";
    } else {
        mainColor = 'rgba(255, 255, 255, 0.5)';
        statusText = "等待手势...";
    }

    ctx.strokeStyle = mainColor;
    ctx.lineWidth = 3;
    ctx.setLineDash([5, 5]);
    ctx.strokeRect(zoneX, zoneY, zoneW, zoneH);
    ctx.setLineDash([]);

    // Status Text
    if (statusText) {
        ctx.font = "bold 16px 'ZCOOL KuaiLe', sans-serif";
        ctx.fillStyle = mainColor;
        ctx.shadowColor = "rgba(0,0,0,0.8)";
        ctx.shadowBlur = 4;
        ctx.fillText(statusText, 10, 25);
        ctx.shadowBlur = 0;
    }

    // Center Crosshair
    ctx.fillStyle = 'rgba(255, 255, 255, 0.3)';
    ctx.fillRect(w/2 - 1, h/2 - 5, 2, 10);
    ctx.fillRect(w/2 - 5, h/2 - 1, 10, 2);

    if (result.landmarks) {
      for (const landmarks of result.landmarks) {
        drawConnectors(ctx, landmarks, HandLandmarker.HAND_CONNECTIONS, { color: "rgba(255,255,255,0.3)", lineWidth: 2 });
        drawLandmarks(ctx, landmarks, { color: mainColor, lineWidth: 2, radius: 4 });

        // Highlight Cursor (Index Tip)
        const index = landmarks[8];
        ctx.beginPath();
        ctx.arc(index.x * w, index.y * h, 10, 0, 2 * Math.PI);
        ctx.fillStyle = mainColor;
        ctx.fill();
        ctx.strokeStyle = "#FFFFFF";
        ctx.lineWidth = 2;
        ctx.stroke();
      }
    }
  };

  const drawConnectors = (ctx: CanvasRenderingContext2D, landmarks: any[], connections: any[], style: any) => {
      ctx.strokeStyle = style.color;
      ctx.lineWidth = style.lineWidth;
      for (const conn of connections) {
          const start = landmarks[conn.start];
          const end = landmarks[conn.end];
          if (start && end) {
            ctx.beginPath();
            ctx.moveTo(start.x * canvasRef.current!.width, start.y * canvasRef.current!.height);
            ctx.lineTo(end.x * canvasRef.current!.width, end.y * canvasRef.current!.height);
            ctx.stroke();
          }
      }
  };

  const drawLandmarks = (ctx: CanvasRenderingContext2D, landmarks: any[], style: any) => {
      ctx.fillStyle = style.color;
      for (const lm of landmarks) {
          ctx.beginPath();
          ctx.arc(lm.x * canvasRef.current!.width, lm.y * canvasRef.current!.height, style.radius, 0, 2 * Math.PI);
          ctx.fill();
      }
  };

  return (
    <div className="absolute bottom-4 right-4 z-50 flex flex-col items-end gap-3 animate-fade-in pointer-events-auto">

      {/* Camera Feed Container */}
      <div className={`relative rounded-2xl overflow-hidden border-4 border-yellow-400 shadow-[0_0_20px_rgba(255,215,0,0.5)] bg-black transition-all duration-300 ease-in-out origin-bottom-right ${
          isExpanded 
            ? 'w-[240px] h-[180px] opacity-100 scale-100 mb-2' 
            : 'w-[200px] h-[150px] opacity-0 scale-50 absolute bottom-0 right-0 -z-50 pointer-events-none'
        }`}>
        <video 
            ref={videoRef} 
            className="w-full h-full object-cover -scale-x-100" 
            autoPlay 
            playsInline 
            muted
        />
        <canvas 
            ref={canvasRef} 
            width={240}
            height={180}
            className="absolute top-0 left-0 w-full h-full -scale-x-100" 
        />

        {permissionError && (
          <div className="absolute inset-0 bg-black/90 flex flex-col items-center justify-center p-4 text-center z-10 gap-2">
             <div className="text-red-400 font-bold text-xs">
                无法访问摄像头<br/>请检查权限设置
             </div>
             <button 
               onClick={() => startWebcam()}
               className="bg-red-500 hover:bg-red-600 text-white text-[10px] px-3 py-1 rounded-full border border-red-400"
             >
               重试
             </button>
          </div>
        )}
      </div>

      {/* Control Bar */}
      <div className="flex items-center gap-3">
         {/* Status Pill */}
         <div className="bg-black/80 backdrop-blur-md text-white pl-4 pr-1 py-1.5 rounded-full border border-green-500/30 shadow-lg flex items-center gap-3">
            <div className="flex items-center gap-2">
               {/* Status Dot */}
               <span className={`w-2 h-2 rounded-full ${loading ? 'bg-yellow-400 animate-ping' : 'bg-green-500 animate-pulse'}`}></span>
               <span className="text-xs font-bold font-mono text-green-400 tracking-wide">
                 {loading ? loadingStatus : "魔法手势 ON"}
               </span>
            </div>

            {/* Show/Hide Camera Toggle */}
            <button 
              onClick={() => setIsExpanded(!isExpanded)}
              className="bg-gray-800 hover:bg-gray-700 text-gray-300 hover:text-white px-3 py-1 rounded-full text-[10px] font-bold transition-colors border border-gray-600 uppercase"
              title={isExpanded ? "隐藏摄像头" : "显示摄像头"}
            >
              {isExpanded ? "隐藏画面" : "显示画面"}
            </button>
         </div>

         {/* Close Button */}
         <button 
            onClick={onClose}
            className="w-10 h-10 bg-red-500 hover:bg-red-400 text-white rounded-full flex items-center justify-center shadow-lg border-2 border-white active:scale-95 transition-all"
            title="关闭手势控制"
         >
            <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3" strokeLinecap="round" strokeLinejoin="round">
               <line x1="18" y1="6" x2="6" y2="18"></line>
               <line x1="6" y1="6" x2="18" y2="18"></line>
            </svg>
         </button>
      </div>

    </div>
  );
};

import React, { useEffect, useRef, useState } from 'react';
import { FilesetResolver, HandLandmarker, HandLandmarkerResult } from '@mediapipe/tasks-vision';

interface GestureControllerProps {
  onControl: (dx: number, dy: number, gestureType: 'rotate' | 'zoom') => void;
  onClose: () => void;
}

type HandAction = 'zoom-in' | 'zoom-out' | 'neutral';

export const GestureController: React.FC<GestureControllerProps> = ({ onControl, onClose }) => {
  const videoRef = useRef<HTMLVideoElement>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);

  const [loading, setLoading] = useState(true);
  const [loadingStatus, setLoadingStatus] = useState("正在启动...");
  const [permissionError, setPermissionError] = useState(false);
  const [isExpanded, setIsExpanded] = useState(true); // Default visible for kids

  const landmarkerRef = useRef<HandLandmarker | null>(null);
  const requestRef = useRef<number>(0);
  const isLoopRunning = useRef(false);

  // Smoothing variables
  const lerpedX = useRef(0);
  const lerpedY = useRef(0);

  // Initialize MediaPipe
  useEffect(() => {
    let isMounted = true;
    const init = async () => {
      setLoadingStatus("加载AI模型...");
      try {
        const vision = await FilesetResolver.forVisionTasks(
          "https://cdn.jsdelivr.net/npm/@mediapipe/tasks-vision@0.10.8/wasm"
        );

        if (!isMounted) return;

        landmarkerRef.current = await HandLandmarker.createFromOptions(vision, {
          baseOptions: {
            modelAssetPath: `https://storage.googleapis.com/mediapipe-models/hand_landmarker/hand_landmarker/float16/1/hand_landmarker.task`,
            delegate: "GPU"
          },
          runningMode: "VIDEO",
          numHands: 1
        });

        if (isMounted) startWebcam();
      } catch (error) {
        console.error("Error initializing MediaPipe:", error);
        if (isMounted) { setPermissionError(true); setLoading(false); }
      }
    };
    init();

    return () => {
      isMounted = false;
      stopLoop();
      if (videoRef.current && videoRef.current.srcObject) {
        const tracks = (videoRef.current.srcObject as MediaStream).getTracks();
        tracks.forEach(t => t.stop());
      }
    };
  }, []);

  const stopLoop = () => {
    if (requestRef.current) {
        cancelAnimationFrame(requestRef.current);
        requestRef.current = 0;
    }
    isLoopRunning.current = false;
  };

  const startWebcam = async () => {
    if (!videoRef.current) return;
    setLoading(true);
    setLoadingStatus("打开摄像头...");
    setPermissionError(false);

    try {
      const constraints = { 
        video: { width: { ideal: 320 }, height: { ideal: 240 }, facingMode: 'user' } 
      };
      const stream = await navigator.mediaDevices.getUserMedia(constraints);

      if (videoRef.current) {
          videoRef.current.srcObject = stream;
          const beginPrediction = () => {
              if (isLoopRunning.current) return;
              setLoading(false);
              predictWebcam();
          };
          if (videoRef.current.readyState >= 2) beginPrediction();
          else videoRef.current.onloadeddata = () => beginPrediction();

          setTimeout(() => { if (loading) beginPrediction(); }, 3000);
          await videoRef.current.play();
      }
    } catch (err) {
      console.error("Webcam error:", err);
      setPermissionError(true);
      setLoading(false);
    }
  };

  const detectHandAction = (landmarks: any[]): HandAction => {
    if (!landmarks || landmarks.length === 0) return 'neutral';

    const thumbTip = landmarks[4];
    const indexTip = landmarks[8];
    const wrist = landmarks[0];

    // 1. Calculate Pinch Distance (Thumb to Index)
    const pinchDist = Math.hypot(thumbTip.x - indexTip.x, thumbTip.y - indexTip.y);

    // 2. Calculate Fingers Extended for Fist Detection
    const fingers = [
        { tip: 8, pip: 6 },  // Index
        { tip: 12, pip: 10 }, // Middle
        { tip: 16, pip: 14 }, // Ring
        { tip: 20, pip: 18 }  // Pinky
    ];
    let extendedCount = 0;
    fingers.forEach(({ tip: tipIdx, pip: pipIdx }) => {
      const tip = landmarks[tipIdx];
      const pip = landmarks[pipIdx];
      const dTip = Math.hypot(tip.x - wrist.x, tip.y - wrist.y);
      const dPip = Math.hypot(pip.x - wrist.x, pip.y - wrist.y);
      if (dTip > dPip * 1.1) extendedCount++;
    });

    // LOGIC:
    // Priority 1: Pinch (Zoom In) - Distinct gesture "OK" sign
    if (pinchDist < 0.05) return 'zoom-in';

    // Priority 2: Fist (Zoom Out) - 0 or 1 finger extended (sometimes index curls lazily)
    if (extendedCount <= 1) return 'zoom-out';

    // Default: Open Hand / Pointing -> Neutral (Just Rotate)
    return 'neutral';
  };

  const predictWebcam = () => {
    isLoopRunning.current = true;
    if (!landmarkerRef.current || !videoRef.current || !canvasRef.current) return;

    if (videoRef.current.videoWidth === 0) {
        requestRef.current = requestAnimationFrame(predictWebcam);
        return;
    }

    const startTimeMs = performance.now();
    let result: HandLandmarkerResult | null = null;
    try {
        result = landmarkerRef.current.detectForVideo(videoRef.current, startTimeMs);
    } catch (e) {}

    let action: HandAction = 'neutral';
    let handCenter = { x: 0.5, y: 0.5 };

    if (result && result.landmarks && result.landmarks.length > 0) {
        const landmarks = result.landmarks[0];
        action = detectHandAction(landmarks);

        // Use Wrist(0) and Middle Knuckle(9) midpoint for stable center tracking
        // Index tip (8) moves too much when pinching
        const wrist = landmarks[0];
        const middleMCP = landmarks[9];
        handCenter = {
            x: (wrist.x + middleMCP.x) / 2,
            y: (wrist.y + middleMCP.y) / 2
        };
    } else {
        // Reset to center if hand lost
        handCenter = { x: 0.5, y: 0.5 };
    }

    processGestures(handCenter, action, !!(result && result.landmarks.length > 0));
    if (result) draw(result, action, handCenter);

    requestRef.current = requestAnimationFrame(predictWebcam);
  };

  const processGestures = (pos: {x: number, y: number}, action: HandAction, hasHand: boolean) => {
    if (!hasHand) {
        // Smoothly return to 0
        lerpedX.current = lerpedX.current * 0.8;
        lerpedY.current = lerpedY.current * 0.8;
        onControl(0, 0, 'rotate');
        return;
    }

    // 1. Joystick Logic (Rotation)
    // Center is 0.5, 0.5. 
    // Calculate deviation from center
    const rawDx = (pos.x - 0.5) * 2; // -1 to 1
    const rawDy = (pos.y - 0.5) * 2; // -1 to 1

    // Apply Deadzone (Center 10% is neutral)
    const deadzone = 0.1;
    let targetDx = 0;
    let targetDy = 0;

    if (Math.abs(rawDx) > deadzone) targetDx = rawDx;
    if (Math.abs(rawDy) > deadzone) targetDy = rawDy;

    // Smooth the input (Lerp) to prevent jitter
    const alpha = 0.15; // Smoothing factor
    lerpedX.current += (targetDx - lerpedX.current) * alpha;
    lerpedY.current += (targetDy - lerpedY.current) * alpha;

    // Send Rotation Command
    // Multiplier 2.0 makes it responsive
    onControl(lerpedX.current * 4.0, lerpedY.current * 2.0, 'rotate');

    // 2. Zoom Logic
    // Only zoom if we are actively pinching or making a fist
    if (action === 'zoom-in') {
        onControl(0, 1.0, 'zoom'); // +1 for In
    } else if (action === 'zoom-out') {
        onControl(0, -1.0, 'zoom'); // -1 for Out
    }
  };

  const draw = (result: HandLandmarkerResult, action: HandAction, handPos: {x: number, y: number}) => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;
    const w = canvas.width;
    const h = canvas.height;

    ctx.clearRect(0, 0, w, h);

    // 1. Draw Background Overlay
    ctx.fillStyle = 'rgba(0, 0, 0, 0.3)';
    ctx.fillRect(0, 0, w, h);

    // 2. Draw "Joystick" Base (Center)
    ctx.beginPath();
    ctx.arc(w/2, h/2, 10, 0, 2 * Math.PI);
    ctx.fillStyle = 'rgba(255, 255, 255, 0.3)';
    ctx.fill();
    ctx.strokeStyle = 'rgba(255, 255, 255, 0.5)';
    ctx.stroke();

    if (result.landmarks && result.landmarks.length > 0) {
        const handX = handPos.x * w;
        const handY = handPos.y * h;

        // Determine Color based on Action
        let color = '#3b82f6'; // Blue (Neutral/Rotate)
        let glowColor = 'rgba(59, 130, 246, 0.5)';
        let label = "🖐 移动";

        if (action === 'zoom-in') {
            color = '#22c55e'; // Green
            glowColor = 'rgba(34, 197, 94, 0.5)';
            label = "👌 放大";
        } else if (action === 'zoom-out') {
            color = '#ef4444'; // Red
            glowColor = 'rgba(239, 68, 68, 0.5)';
            label = "✊ 缩小";
        }

        // 3. Draw Tether Line (Elastic band effect)
        ctx.beginPath();
        ctx.moveTo(w/2, h/2);
        ctx.lineTo(handX, handY);
        ctx.strokeStyle = glowColor;
        ctx.lineWidth = 4;
        ctx.setLineDash([5, 5]);
        ctx.stroke();
        ctx.setLineDash([]);

        // 4. Draw Hand Cursor
        ctx.beginPath();
        ctx.arc(handX, handY, 15, 0, 2 * Math.PI);
        ctx.fillStyle = color;
        ctx.fill();
        ctx.strokeStyle = '#ffffff';
        ctx.lineWidth = 2;
        ctx.stroke();

        // 5. Draw Pulse Effect
        ctx.beginPath();
        ctx.arc(handX, handY, 25, 0, 2 * Math.PI);
        ctx.strokeStyle = color;
        ctx.lineWidth = 1;
        ctx.stroke();

        // 6. Draw Label near hand
        ctx.font = "bold 16px 'ZCOOL KuaiLe', sans-serif";
        ctx.fillStyle = "#ffffff";
        ctx.shadowColor = "rgba(0,0,0,1)";
        ctx.shadowBlur = 4;
        ctx.fillText(label, handX + 20, handY + 5);
        ctx.shadowBlur = 0;

        // 7. Draw Skeleton (Subtle)
        const landmarks = result.landmarks[0];
        drawConnectors(ctx, landmarks, HandLandmarker.HAND_CONNECTIONS, { color: "rgba(255,255,255,0.2)", lineWidth: 1 });
    } else {
        // No hand hint
        ctx.font = "14px sans-serif";
        ctx.fillStyle = "rgba(255,255,255,0.6)";
        ctx.textAlign = "center";
        ctx.fillText("把手放在这里", w/2, h/2 + 30);
    }
  };

  const drawConnectors = (ctx: CanvasRenderingContext2D, landmarks: any[], connections: any[], style: any) => {
      ctx.strokeStyle = style.color;
      ctx.lineWidth = style.lineWidth;
      for (const conn of connections) {
          const start = landmarks[conn.start];
          const end = landmarks[conn.end];
          if (start && end) {
            ctx.beginPath();
            ctx.moveTo(start.x * canvasRef.current!.width, start.y * canvasRef.current!.height);
            ctx.lineTo(end.x * canvasRef.current!.width, end.y * canvasRef.current!.height);
            ctx.stroke();
          }
      }
  };

  return (
    <div className="absolute bottom-4 right-4 z-50 flex flex-col items-end gap-3 animate-fade-in pointer-events-auto">

      {/* Camera Feed Container - Slightly larger for easier viewing */}
      <div className={`relative rounded-2xl overflow-hidden border-4 border-blue-500/50 shadow-[0_0_30px_rgba(59,130,246,0.3)] bg-black/80 transition-all duration-300 ease-in-out origin-bottom-right ${
          isExpanded 
            ? 'w-[280px] h-[210px] opacity-100 scale-100 mb-2' 
            : 'w-[200px] h-[150px] opacity-0 scale-50 absolute bottom-0 right-0 -z-50 pointer-events-none'
        }`}>
        <video 
            ref={videoRef} 
            className="w-full h-full object-cover -scale-x-100 opacity-60" 
            autoPlay 
            playsInline 
            muted
        />
        <canvas 
            ref={canvasRef} 
            width={280}
            height={210}
            className="absolute top-0 left-0 w-full h-full -scale-x-100" 
        />

        {/* Instructions Overlay (Always visible lightly) */}
        {!permissionError && !loading && (
             <div className="absolute top-2 left-2 pointer-events-none">
                 <div className="flex flex-col gap-1 text-[10px] text-white/80 font-bold bg-black/40 p-1.5 rounded backdrop-blur-sm">
                    <span className="text-green-400">👌 捏合: 放大</span>
                    <span className="text-red-400">✊ 握拳: 缩小</span>
                    <span className="text-blue-400">🖐 移动: 旋转</span>
                 </div>
             </div>
        )}

        {permissionError && (
          <div className="absolute inset-0 bg-black/90 flex flex-col items-center justify-center p-4 text-center z-10 gap-2">
             <div className="text-red-400 font-bold text-xs">
